        "__import__('os').system('id')",
        "eval('1+1')",
        "exec('import os')",
        "__builtins__['eval']('1')",
    ]

    for payload in payloads:
        mock_eval.reset()
        try:
            result = run_code_snippet(payload)
            if result is not None and "uid=" in str(result):
